    ('<h2 class="split-title" style="color: var(--text);"><span>Giảm thiểu</span><span>Khí nhà kính</span></h2>', '<h2 class="split-title" style="color: var(--text);"><span data-i18n="impactReduce">Giảm thiểu</span><span data-i18n="impactGreenhouse">Khí nhà kính</span></h2>'),
